    TResourceType target)
    where TResourceType : class
```

**Usage (Instance Methods):**
```csharp
public class FileResourceProvider
{
    public FileResourceProvider(string basePath)
    {
        BasePath = basePath;
    }

    public string BasePath { get; }

    [McpServerResource(
        Name = "file_content",
        UriTemplate = "file/{filename}"
    )]
    public string GetFileContent(string filename)
    {
        return File.ReadAllText(Path.Combine(BasePath, filename));
    }
}

// Register instance resources
var provider = new FileResourceProvider("/data");
builder.Services.AddMcpServer()
    .WithHttpTransport()
    .WithResources(provider);
