1. using ModelContextProtocol.Server;
2. using System.ComponentModel;
3. 
4. var builder = WebApplication.CreateBuilder(args);
5. 
6. builder.Services
7.     .AddMcpServer(options =>
8.     {
9.         options.ServerInfo = new() { Name = "MyMcpServer", Version = "1.0.0" };
10.     })
11.     .WithHttpTransport()
12.     .WithTools<WeatherTools>()
13.     .WithResources<ConfigResources>();
14. 
15. var app = builder.Build();
16. 
17. app.MapMcp();
18. 
19. app.Run();
