21. // ── Tools ────────────────────────────────────────────────────────────────────
22. 
23. public class WeatherTools
24. {
25.     [McpServerTool(Name = "get_weather", Title = "Get Weather", ReadOnly = true, Destructive = false)]
26.     [Description("Returns the current weather for a given city.")]
27.     public static string GetWeather(
28.         [Description("City name, e.g. 'Seattle'")] string city)
29.     {
30.         // Stub — replace with a real API call
31.         return $$"""
32.         {
33.             "city":        "{{city}}",
34.             "temperature": "18°C",
35.             "condition":   "Partly cloudy"
36.         }
37.         """;
38.     }
39. }
40. 
41. // ── Resources ────────────────────────────────────────────────────────────────
42. 
43. public class ConfigResources
44. {
45.     [McpServerResource(
46.         UriTemplate = "config://app/settings",
47.         Name         = "app_settings",
48.         Title        = "Application Settings",
49.         MimeType     = "application/json")]
50.     [Description("Returns the current application configuration.")]
51.     public static string GetAppSettings()
52.     {
53.         return """
54.         {
55.             "maxRetries":   3,
56.             "timeoutMs":    5000,
57.             "featureFlags": {
58.                 "darkMode": true,
59.                 "beta":     false
60.             }
61.         }
62.         """;
63.     }
64. 
65.     [McpServerResource(
66.         UriTemplate = "config://app/settings/{section}",
67.         Name         = "app_settings_section",
68.         Title        = "Application Settings by Section",
69.         MimeType     = "application/json")]
70.     [Description("Returns configuration for a specific section.")]
71.     public static string GetSettingsSection(string section)
72.     {
73.         return section.ToLowerInvariant() switch
74.         {
75.             "featureflags" => """{ "darkMode": true, "beta": false }""",
76.             "limits"       => """{ "maxRetries": 3, "timeoutMs": 5000 }""",
77.             _              => $$"""{ "error": "Unknown section '{{section}}'" }"""
78.         };
79.     }
80. }
81.

